child.stdout.pipe(process.stdout);
child.stderr.pipe(process.stderr);

if (logStream) {
  child.stdout.pipe(logStream);
  child.stderr.pipe(logStream);
}

function forwardSignal(signal) {
  if (!child.killed) {
    child.kill(signal);
  }
}

process.on("SIGINT", () => {
  forwardSignal("SIGINT");
});

process.on("SIGTERM", () => {
  forwardSignal("SIGTERM");
});

child.on("exit", (code) => {
  logStream?.end();
  process.exit(code ?? 0);
});

